#pragma OPENCL EXTENSION cl_khr_fp64 : enable

typedef struct {
  float weight;
  long assign;
  float cost;
} Point_Struct;

inline unsigned int atomic_load_uint(volatile __global unsigned int* addr) {
    return *addr;
}

inline void atomic_add_float(__global float* addr, float val) {
    union {
        unsigned int intVal;
        float floatVal;
    } oldVal;
    union {
        unsigned int intVal;
        float floatVal;
    } newVal;

    do {
        oldVal.intVal = atomic_cmpxchg((volatile __global unsigned int*)addr, 0, 0);
        newVal.floatVal = oldVal.floatVal + val;
    } while (atomic_cmpxchg((volatile __global unsigned int*)addr, oldVal.intVal, newVal.intVal) != oldVal.intVal);
}

__kernel void pgain_kernel(
    __global Point_Struct* p,
    __global float* coord,
    __global float* work_mem,
    __global int* center_table,
    __global char* switch_membership,
    __local float* local_coord,
    const int num,
    const int dim,
    const long x,
    const int K)
{
    int gid = get_global_id(0);
    if (gid >= num) return;

    // Load coordinates of point gid into local memory
    for (int i = get_local_id(0); i < dim; i += get_local_size(0)) {
        local_coord[i] = coord[gid + i * num];
    }
    barrier(CLK_LOCAL_MEM_FENCE);

    float x_cost = 0.0f;
    float current_cost = p[gid].cost;

    // Compute distance between point gid and point x
    float dist_val = 0.0f;
    for (int i = 0; i < dim; i++) {
        float diff = local_coord[i] - coord[x + i * num];
        dist_val += diff * diff;
    }
    x_cost = dist_val * p[gid].weight;

    if (x_cost < current_cost) {
        switch_membership[gid] = 1;
        // No atomic add needed here for work_mem
    } else {
        switch_membership[gid] = 0;
        int assign = p[gid].assign;
        // Atomic add to work_mem at center_table[assign]
        atomic_add_float(&work_mem[center_table[assign]], current_cost - x_cost);
    }
}

